-- Casual fabrics: three colours (composition unknown) + white linen.
INSERT OR IGNORE INTO fabric (id, code, name_i18n, description_i18n, surcharge_minor, available, created_at, updated_at)
VALUES ('fab_riv_tobacco', 'CAS-TOB-01', '{"de":"Tabakbraun","en":"Tobacco Brown","fr":"Brun tabac","it":"Marrone tabacco"}', '{"de":"Ein warmer, ruhiger Braunton mit natürlicher Stoffstruktur. Geeignet für entspannte Hemden und Hosen der Casual Essentials Collection.","en":"A warm, quiet brown tone with a natural fabric texture. Suitable for relaxed shirts and trousers in the Casual Essentials collection.","fr":"Une teinte brune chaude et sobre à la texture naturelle. Adaptée aux chemises et pantalons décontractés de la collection Essentiels Casual.","it":"Una tonalità marrone calda e sobria con texture naturale. Adatta a camicie e pantaloni rilassati della collezione Essenziali Casual."}', 0, 1, '2026-06-26T00:00:00Z', '2026-06-26T00:00:00Z');
INSERT OR IGNORE INTO fabric (id, code, name_i18n, description_i18n, surcharge_minor, available, created_at, updated_at)
VALUES ('fab_riv_olive', 'CAS-OLV-01', '{"de":"Olivgrün","en":"Olive Green","fr":"Vert olive","it":"Verde oliva"}', '{"de":"Ein gedämpfter Olivton mit natürlicher Struktur. Ruhig, vielseitig und gut kombinierbar.","en":"A muted olive tone with a natural texture. Quiet, versatile, and easy to combine.","fr":"Une teinte olive sourde à la texture naturelle. Sobre, polyvalente et facile à associer.","it":"Una tonalità verde oliva attenuata con texture naturale. Sobria, versatile e facile da abbinare."}', 0, 1, '2026-06-26T00:00:00Z', '2026-06-26T00:00:00Z');
INSERT OR IGNORE INTO fabric (id, code, name_i18n, description_i18n, surcharge_minor, available, created_at, updated_at)
VALUES ('fab_riv_sand', 'CAS-SND-01', '{"de":"Sandbeige","en":"Sand Beige","fr":"Beige sable","it":"Beige sabbia"}', '{"de":"Ein heller, neutraler Sandton mit leichter, natürlicher Wirkung. Ideal für warme Tage und ruhige Kombinationen.","en":"A light neutral sand tone with an easy natural character. Ideal for warm days and calm combinations.","fr":"Une teinte sable claire et neutre au caractère naturel. Idéale pour les journées chaudes et les associations sobres.","it":"Una tonalità sabbia chiara e neutra dal carattere naturale. Ideale per giornate calde e abbinamenti sobri."}', 0, 1, '2026-06-26T00:00:00Z', '2026-06-26T00:00:00Z');
INSERT OR IGNORE INTO fabric (id, code, name_i18n, description_i18n, material, fibre_composition, surcharge_minor, available, created_at, updated_at)
VALUES ('fab_lin_white', 'LIN-WHT-01', '{"de":"Leinen Weiss","en":"White Linen","fr":"Lin blanc","it":"Lino bianco"}', '{"de":"Weisses Leinen mit natürlicher Struktur, leichtem Griff und sommerlichem Charakter.","en":"White linen with a natural texture, lightweight feel, and summer-ready character.","fr":"Lin blanc à la texture naturelle, au toucher léger et au caractère estival.","it":"Lino bianco con texture naturale, mano leggera e carattere estivo."}', 'Linen', '{"linen":100}', 0, 1, '2026-06-26T00:00:00Z', '2026-06-26T00:00:00Z');

-- Casual base models (orderable; placeholder prices; lead time 21/35).
INSERT OR IGNORE INTO base_model (id, garment_type_id, handle, name_i18n, description_i18n, base_price_minor, lead_time_min_days, lead_time_max_days, status, created_at, updated_at)
VALUES ('bm_riviera_shirt', 'gt_shirt', 'camp-collar-shirt', '{"de":"Camp Collar Shirt","en":"Camp Collar Shirt","fr":"Chemise à col camp","it":"Camicia con collo camp"}', '{"de":"Das Camp Collar Shirt ist ein leichtes, kurzärmeliges Hemd für warme Tage und entspannte Smart-Casual-Looks. Der offene Kragen, die klare Knopfleiste und die lockere Silhouette machen es vielseitig tragbar - solo, über einem T-Shirt oder kombiniert mit der passenden Drawstring Trouser. Nach Ihren Massen gefertigt und in drei ruhigen Farben erhältlich.","en":"The Camp Collar Shirt is a lightweight short-sleeve shirt for warm days and relaxed smart-casual dressing. Its open collar, clean button front, and easy silhouette make it versatile - worn on its own, over a T-shirt, or paired with the matching Drawstring Trouser. Made to your measurements and available in three quiet colors.","fr":"La Chemise à col camp est une chemise légère à manches courtes pensée pour les journées chaudes et les tenues smart casual détendues. Son col ouvert, sa patte de boutonnage épurée et sa silhouette souple la rendent polyvalente - portée seule, sur un T-shirt ou avec le Pantalon à cordon assorti. Confectionnée selon vos mesures et disponible en trois couleurs sobres.","it":"La Camicia con collo camp è una camicia leggera a maniche corte pensata per giornate calde e look smart casual rilassati. Il collo aperto, l’abbottonatura pulita e la linea morbida la rendono versatile - da sola, sopra una T-shirt o abbinata al Pantalone con coulisse coordinato. Realizzata sulle tue misure e disponibile in tre colori sobri."}', 16900, 14, 28, 'orderable', '2026-06-26T00:00:00Z', '2026-06-26T00:00:00Z');
INSERT OR IGNORE INTO base_model (id, garment_type_id, handle, name_i18n, description_i18n, base_price_minor, lead_time_min_days, lead_time_max_days, status, created_at, updated_at)
VALUES ('bm_riviera_trouser', 'gt_trouser', 'drawstring-trouser', '{"de":"Drawstring Trouser","en":"Drawstring Trouser","fr":"Pantalon à cordon","it":"Pantalone con coulisse"}', '{"de":"Die Drawstring Trouser verbindet den Komfort einer lockeren Freizeithose mit der sauberen Linie einer massgefertigten Hose. Der elastische Bund mit Kordelzug sorgt für Bewegungsfreiheit, während das gerade Bein ruhig und gepflegt wirkt. Ideal für warme Tage, Reisen und entspannte Smart-Casual-Looks - allein getragen oder kombiniert mit dem passenden Camp Collar Shirt.","en":"The Drawstring Trouser combines the comfort of a relaxed casual pant with the clean look of a made-to-measure trouser. The elastic waistband and drawstring offer easy movement, while the straight leg keeps the silhouette refined and understated. Designed for warm days, travel, and relaxed smart-casual dressing - worn on its own or paired with the matching Camp Collar Shirt.","fr":"Le Pantalon à cordon associe le confort d’un pantalon décontracté à la ligne soignée d’un vêtement sur mesure. La taille élastique avec cordon offre une grande liberté de mouvement, tandis que la jambe droite conserve une silhouette élégante et discrète. Pensé pour les journées chaudes, les voyages et les tenues smart casual détendues - seul ou avec la Chemise à col camp assortie.","it":"Il Pantalone con coulisse unisce il comfort di un pantalone rilassato alla linea pulita di un capo su misura. La vita elasticizzata con coulisse offre libertà di movimento, mentre la gamba dritta mantiene una silhouette curata e discreta. Pensato per giornate calde, viaggi e look smart casual rilassati - da solo o abbinato alla Camicia con collo camp coordinata."}', 18900, 14, 28, 'orderable', '2026-06-26T00:00:00Z', '2026-06-26T00:00:00Z');
INSERT OR IGNORE INTO base_model (id, garment_type_id, handle, name_i18n, description_i18n, base_price_minor, lead_time_min_days, lead_time_max_days, status, created_at, updated_at)
VALUES ('bm_linen_shirt', 'gt_shirt', 'linen-essential-shirt', '{"de":"Linen Essential Shirt","en":"Linen Essential Shirt","fr":"Chemise Essential en lin","it":"Camicia Essential in lino"}', '{"de":"Das Linen Essential Shirt ist ein klassisches Leinenhemd für warme Tage und ruhige, gepflegte Looks. Der leichte Stoff, die natürliche Struktur und die klare Silhouette machen es vielseitig tragbar: offen über einem T-Shirt, sauber kombiniert mit Chino oder entspannt zu einer Sommerhose. Nach Ihren Massen gefertigt und bewusst schlicht gehalten.","en":"The Linen Essential Shirt is a classic linen shirt designed for warm days and understated dressing. Its lightweight fabric, natural texture, and clean silhouette make it easy to wear open over a T-shirt, paired with chinos, or styled casually with relaxed summer trousers. Made to your measurements and kept deliberately simple.","fr":"La Chemise Essential en lin est une chemise classique pensée pour les journées chaudes et les tenues sobres. Son tissu léger, sa texture naturelle et sa silhouette épurée la rendent facile à porter ouverte sur un T-shirt, avec un chino ou avec un pantalon d’été plus détendu. Confectionnée selon vos mesures et volontairement simple.","it":"La Camicia Essential in lino è una camicia classica pensata per le giornate calde e per uno stile sobrio. Il tessuto leggero, la texture naturale e la linea pulita la rendono facile da indossare aperta sopra una T-shirt, con un chino o con pantaloni estivi rilassati. Realizzata sulle tue misure e volutamente essenziale."}', 18900, 14, 28, 'orderable', '2026-06-26T00:00:00Z', '2026-06-26T00:00:00Z');

