-- New smart-casual entities
INSERT OR IGNORE INTO base_model (id, garment_type_id, handle, name_i18n, description_i18n, base_price_minor, lead_time_min_days, lead_time_max_days, status, created_at, updated_at)
VALUES ('bm_kt_smart', 'gt_shirt', 'smart-casual-shirt', '{"de": "Smart Casual Shirt", "en": "Smart Casual Shirt", "fr": "Chemise smart casual", "it": "Camicia smart casual"}', '{"de": "Das Smart Casual Shirt ist das vielseitigste Hemd im Sortiment: gepflegt genug fuers Buero, entspannt genug fuer den Abend. Klarer Kragen, weicher Griff, ruhige Silhouette. Nach Ihren Massen gefertigt.", "en": "The Smart Casual Shirt is the most versatile shirt in the range: polished enough for the office, relaxed enough for the evening. Clean collar, soft hand feel, calm silhouette. Made to your measurements.", "fr": "La chemise smart casual est la plus polyvalente de la gamme: assez soignee pour le bureau, assez detendue pour le soir. Col net, toucher doux, silhouette sobre. Confectionnee selon vos mesures.", "it": "La camicia smart casual e la piu versatile della gamma: curata per l''ufficio, rilassata per la sera. Collo pulito, mano morbida, silhouette sobria. Realizzata sulle tue misure."}', 16900, 14, 28, 'orderable', '2026-07-09T08:00:00Z', '2026-07-09T08:00:00Z');
INSERT OR IGNORE INTO base_model (id, garment_type_id, handle, name_i18n, description_i18n, base_price_minor, lead_time_min_days, lead_time_max_days, status, created_at, updated_at)
VALUES ('bm_kt_camp', 'gt_shirt', 'camp-collar-shirt', '{"de": "Camp Collar Shirt", "en": "Camp Collar Shirt", "fr": "Chemise à col camp", "it": "Camicia con collo camp"}', '{"de": "Das Camp Collar Shirt ist ein leichtes, kurzärmeliges Hemd für warme Tage und entspannte Smart-Casual-Looks. Der offene Kragen, die klare Knopfleiste und die lockere Silhouette machen es vielseitig tragbar - solo, über einem T-Shirt oder kombiniert mit der passenden Drawstring Trouser. Nach Ihren Massen gefertigt und in drei ruhigen Farben erhältlich.", "en": "The Camp Collar Shirt is a lightweight short-sleeve shirt for warm days and relaxed smart-casual dressing. Its open collar, clean button front, and easy silhouette make it versatile - worn on its own, over a T-shirt, or paired with the matching Drawstring Trouser. Made to your measurements and available in three quiet colors.", "fr": "La Chemise à col camp est une chemise légère à manches courtes pensée pour les journées chaudes et les tenues smart casual détendues. Son col ouvert, sa patte de boutonnage épurée et sa silhouette souple la rendent polyvalente - portée seule, sur un T-shirt ou avec le Pantalon à cordon assorti. Confectionnée selon vos mesures et disponible en trois couleurs sobres.", "it": "La Camicia con collo camp è una camicia leggera a maniche corte pensata per giornate calde e look smart casual rilassati. Il collo aperto, l’abbottonatura pulita e la linea morbida la rendono versatile - da sola, sopra una T-shirt o abbinata al Pantalone con coulisse coordinato. Realizzata sulle tue misure e disponibile in tre colori sobri."}', 16900, 14, 28, 'orderable', '2026-07-09T08:00:00Z', '2026-07-09T08:00:00Z');
INSERT OR IGNORE INTO base_model (id, garment_type_id, handle, name_i18n, description_i18n, base_price_minor, lead_time_min_days, lead_time_max_days, status, created_at, updated_at)
VALUES ('bm_kt_linen', 'gt_shirt', 'linen-shirt', '{"de": "Linen Shirt", "en": "Linen Shirt", "fr": "Chemise en lin", "it": "Camicia di lino"}', '{"de": "Das Linen Essential Shirt ist ein klassisches Leinenhemd für warme Tage und ruhige, gepflegte Looks. Der leichte Stoff, die natürliche Struktur und die klare Silhouette machen es vielseitig tragbar: offen über einem T-Shirt, sauber kombiniert mit Chino oder entspannt zu einer Sommerhose. Nach Ihren Massen gefertigt und bewusst schlicht gehalten.", "en": "The Linen Essential Shirt is a classic linen shirt designed for warm days and understated dressing. Its lightweight fabric, natural texture, and clean silhouette make it easy to wear open over a T-shirt, paired with chinos, or styled casually with relaxed summer trousers. Made to your measurements and kept deliberately simple.", "fr": "La Chemise Essential en lin est une chemise classique pensée pour les journées chaudes et les tenues sobres. Son tissu léger, sa texture naturelle et sa silhouette épurée la rendent facile à porter ouverte sur un T-shirt, avec un chino ou avec un pantalon d’été plus détendu. Confectionnée selon vos mesures et volontairement simple.", "it": "La Camicia Essential in lino è una camicia classica pensata per le giornate calde e per uno stile sobrio. Il tessuto leggero, la texture naturale e la linea pulita la rendono facile da indossare aperta sopra una T-shirt, con un chino o con pantaloni estivi rilassati. Realizzata sulle tue misure e volutamente essenziale."}', 18900, 14, 28, 'orderable', '2026-07-09T08:00:00Z', '2026-07-09T08:00:00Z');
INSERT OR IGNORE INTO base_model (id, garment_type_id, handle, name_i18n, description_i18n, base_price_minor, lead_time_min_days, lead_time_max_days, status, created_at, updated_at)
VALUES ('bm_kt_oxford', 'gt_shirt', 'oxford-shirt', '{"de": "Oxford Shirt", "en": "Oxford Shirt", "fr": "Chemise Oxford", "it": "Camicia Oxford"}', '{"de": "Das Oxford Business Shirt ist ein klares, vielseitiges Hemd für Büro, Meetings und gepflegte Alltagslooks. Der klassische Kragen, die saubere Knopfleiste und die strukturierte Oberfläche sorgen für einen ruhigen, professionellen Eindruck. Nach Ihren Massen gefertigt und in Weiss oder Hellblau erhältlich.", "en": "The Oxford Business Shirt is a clean, versatile shirt for the office, meetings, and refined daily wear. Its classic collar, neat button front, and structured surface create a calm, professional impression. Made to your measurements and available in white or light blue.", "fr": "La Chemise Business Oxford est une chemise nette et polyvalente pour le bureau, les réunions et les tenues quotidiennes soignées. Son col classique, sa patte de boutonnage épurée et sa surface structurée créent une impression sobre et professionnelle. Confectionnée selon vos mesures et disponible en blanc ou bleu clair.", "it": "La Camicia Business Oxford è una camicia pulita e versatile per ufficio, riunioni e look quotidiani curati. Il collo classico, l’abbottonatura ordinata e la superficie strutturata creano un’impressione sobria e professionale. Realizzata sulle tue misure e disponibile in bianco o azzurro."}', 16900, 14, 28, 'orderable', '2026-07-09T08:00:00Z', '2026-07-09T08:00:00Z');
INSERT OR IGNORE INTO base_model (id, garment_type_id, handle, name_i18n, description_i18n, base_price_minor, lead_time_min_days, lead_time_max_days, status, created_at, updated_at)
VALUES ('bm_kt_chino', 'gt_trouser', 'chino', '{"de": "Chino", "en": "Chino", "fr": "Chino", "it": "Chino"}', '{"de": "Der Chino ist die unkomplizierte Hose fuer jeden Tag: glatte Front, gerades Bein, weicher Baumwollstoff. Er begleitet Hemd und Sakko ebenso wie T-Shirt und Strick. Nach Ihren Massen gefertigt, in Sand oder Marine.", "en": "The Chino is the uncomplicated everyday trouser: flat front, straight leg, soft cotton fabric. It works with a shirt and jacket as well as with a T-shirt and knitwear. Made to your measurements, in sand or navy.", "fr": "Le chino est le pantalon simple de tous les jours: devant plat, jambe droite, coton doux. Il accompagne chemise et veste comme t-shirt et maille. Confectionne selon vos mesures, en sable ou marine.", "it": "Il chino e il pantalone semplice di ogni giorno: davanti liscio, gamba dritta, cotone morbido. Sta bene con camicia e giacca come con t-shirt e maglia. Realizzato sulle tue misure, in sabbia o blu navy."}', 18900, 14, 28, 'orderable', '2026-07-09T08:00:00Z', '2026-07-09T08:00:00Z');
INSERT OR IGNORE INTO base_model (id, garment_type_id, handle, name_i18n, description_i18n, base_price_minor, lead_time_min_days, lead_time_max_days, status, created_at, updated_at)
VALUES ('bm_kt_drawstring', 'gt_trouser', 'drawstring-trouser', '{"de": "Drawstring Trouser", "en": "Drawstring Trouser", "fr": "Pantalon à cordon", "it": "Pantalone con coulisse"}', '{"de": "Die Drawstring Trouser verbindet den Komfort einer lockeren Freizeithose mit der sauberen Linie einer massgefertigten Hose. Der elastische Bund mit Kordelzug sorgt für Bewegungsfreiheit, während das gerade Bein ruhig und gepflegt wirkt. Ideal für warme Tage, Reisen und entspannte Smart-Casual-Looks - allein getragen oder kombiniert mit dem passenden Camp Collar Shirt.", "en": "The Drawstring Trouser combines the comfort of a relaxed casual pant with the clean look of a made-to-measure trouser. The elastic waistband and drawstring offer easy movement, while the straight leg keeps the silhouette refined and understated. Designed for warm days, travel, and relaxed smart-casual dressing - worn on its own or paired with the matching Camp Collar Shirt.", "fr": "Le Pantalon à cordon associe le confort d’un pantalon décontracté à la ligne soignée d’un vêtement sur mesure. La taille élastique avec cordon offre une grande liberté de mouvement, tandis que la jambe droite conserve une silhouette élégante et discrète. Pensé pour les journées chaudes, les voyages et les tenues smart casual détendues - seul ou avec la Chemise à col camp assortie.", "it": "Il Pantalone con coulisse unisce il comfort di un pantalone rilassato alla linea pulita di un capo su misura. La vita elasticizzata con coulisse offre libertà di movimento, mentre la gamba dritta mantiene una silhouette curata e discreta. Pensato per giornate calde, viaggi e look smart casual rilassati - da solo o abbinato alla Camicia con collo camp coordinata."}', 18900, 14, 28, 'orderable', '2026-07-09T08:00:00Z', '2026-07-09T08:00:00Z');

